#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[5];
        scanf("%s", S);
        int len = strlen(S);
        int minI = -1;
        for (int B = 2; B <= 36; B++) {
            for (int I = 1; ; I++) {
                int digits[4] = {0};
                int temp = I;
                int idx = 0;
                while (temp > 0) {
                    digits[idx++] = temp % B;
                    temp /= B;
                }
                int product = 1;
                for (int i = 0; i < idx; i++) {
                    product *= digits[i];
                }
                int value = 0;
                for (int i = 0; i < len; i++) {
                    if (S[i] >= '0' && S[i] <= '9') {
                        value = value * B + (S[i] - '0');
                    } else {
                        value = value * B + (S[i] - 'A' + 10);
                    }
                }
                if (product == value) {
                    minI = I;
                    break;
                }
                if (I > 10000) break;
            }
            if (minI != -1) break;
        }
        printf("%d\n", minI);
    }
    return 0;
}

