def solve(S):
    for B in range(2, 37):
        for I in range(1, 10001):
            digits = []
            temp = I
            while temp > 0:
                digits.append(temp % B)
                temp //= B
            product = 1
            for digit in digits:
                product *= digit
            value = 0
            for i in range(len(S)):
                if S[i].isdigit():
                    value = value * B + int(S[i])
                else:
                    value = value * B + ord(S[i]) - ord('A') + 10
            if product == value:
                return I
    return -1

T = int(input())
for _ in range(T):
    S = input()
    print(solve(S))

